class ItemRarity(str, Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"


@dataclass
class Item:
    item_id: str
    name: str
    rarity: ItemRarity
    value: int
    owner_id: Optional[str] = None
    tradeable: bool = True

    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "rarity": self.rarity.value,
            "value": self.value,
            "owner_id": self.owner_id,
            "tradeable": self.tradeable,
        }


@dataclass
class Player:
    player_id: str
    username: str
    inventory: Dict[str, Item] = field(default_factory=dict)
    gold: int = 1000
    online: bool = False
